typedef long long ll;

ll mod = 1e9 + 7;
int n, q;
vector<pair<ll, ll>> events;
vector<ll> sum;
vector<ll> prod;
vector<ll> next_prod_eqm2;
vector<ll> weird_sum;

ll ssum(ll l, ll r, int app_mod=1){
    if(l > r) return 0;
    if(app_mod){
        return (mod + sum[r] - sum[l - 1]) % mod;
    } else {
        return sum[r] - sum[l - 1];
    }
}

