    events.resize(n + 2);
    sum.resize(n + 2);
    prod.resize(n + 2);
    next_prod_eqm2.resize(n + 2);
    weird_sum.resize(n + 2);

    prod[0] = 1;
    for(int i = 1; i <= n; i++){
        cin >> events[i].st >> events[i].nd;
        sum[i] = sum[i - 1] + events[i].st;
        prod[i] = (prod[i - 1] * max(events[i].nd, 1LL)) % mod;    
    }

    int last = n + 1;
    for(int i = n + 1; i >= 0; i--){
        next_prod_eqm2[i] = last;
        if(events[i].nd > 1) last = i;
    }

    ll multi = 1;
    for(int i = n; i >= 0; i--){
        weird_sum[i] = weird_sum[i + 1];
        if(events[i].nd > 1){
            multi = (multi * events[i].nd) % mod;
        } else {
            weird_sum[i] = (weird_sum[i] + events[i].st * multi) % mod;
        }
    }

    while(q--){
        solve();
    }
    return 0;
